1	// MHPCO Claim Office - Policy quoting and claim processing system
2	
3	const ITEM_TYPE_PREMIUMS: Record<string, number> = {
4	  Sword: 50,
5	  Amulet: 100,
6	  Staff: 75,
7	  Potion: 60,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE = 1.1;
11	const LOYALTY_DISCOUNT = 0.8; // -20% discount for 2+ years
12	const CURSED_ITEM_SURCHARGE = 1.5;
13	const HIGH_ENCHANTMENT_SURCHARGE = 1.3; // +30% for enchantmentLevel >= 5
14	
15	export interface Item {
16	  type: string;
17	  insuranceModifier?: string;
18	  yearsInsured?: number;
19	  cursed?: boolean;
20	  enchantmentLevel?: number;
21	}
22	
23	const applyModifier = (value: number, multiplier: number, shouldApply: boolean): number => {
24	  return shouldApply ? value * multiplier : value;
25	};
26	
27	const applyModifiers = (premium: number, item: Item): number => {
28	  const modifiers = [
29	    { multiplier: FIRST_INSURANCE_SURCHARGE, condition: item.insuranceModifier === "first" },
30	    { multiplier: LOYALTY_DISCOUNT, condition: item.yearsInsured !== undefined && item.yearsInsured >= 2 },
31	    { multiplier: CURSED_ITEM_SURCHARGE, condition: item.cursed === true },
32	    { multiplier: HIGH_ENCHANTMENT_SURCHARGE, condition: item.enchantmentLevel !== undefined && item.enchantmentLevel >= 5 },
33	  ];
34	
35	  return modifiers.reduce((adjusted, mod) => applyModifier(adjusted, mod.multiplier, mod.condition), premium);
36	};
37	
38	const roundUpInMHPCOsFavor = (value: number): number => {
39	  const standardRound = Math.round(value);
40	  return value > standardRound ? standardRound + 1 : standardRound;
41	};
42	
43	export function quotePolicy(items: Item[]): number {
44	  const total = items.reduce((sum, item) => {
45	    if (!(item.type in ITEM_TYPE_PREMIUMS)) {
46	      throw new Error(`Unknown item type: ${item.type}`);
47	    }
48	    const basePremium = ITEM_TYPE_PREMIUMS[item.type];
49	    const adjustedPremium = applyModifiers(basePremium, item);
50	    return sum + Math.round(adjustedPremium * 100) / 100;
51	  }, 0);
52	  return roundUpInMHPCOsFavor(total);
53	}
54	
55	const INDIVIDUAL_COMPONENT_PRICE = 25;
56	const COMPONENT_BLOCK_SIZE = 3;
57	const COMPONENT_BLOCK_PRICE = 60;
58	
59	const CLAIM_DEDUCTIBLE = 100;
60	const INSURANCE_CAP_MULTIPLIER = 2;
61	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
62	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
63	
64	export function quoteComponent(items: Item[]): number {
65	  return items.length === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : INDIVIDUAL_COMPONENT_PRICE;
66	}
67	
68	const applyInsuranceCap = (amount: number, insuranceSum: number, dragonMaterial: boolean): number => {
69	  if (dragonMaterial) {
70	    return amount;
71	  }
72	  const cap = insuranceSum * INSURANCE_CAP_MULTIPLIER;
73	  return Math.min(amount, cap);
74	};
75	
76	const applyEnchantmentReduction = (reimbursement: number, enchantmentLevel?: number): number => {
77	  if (enchantmentLevel !== undefined && enchantmentLevel >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD) {
78	    return reimbursement * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
79	  }
80	  return reimbursement;
81	};
82	
83	const validateItemInPolicy = (itemType?: string): void => {
84	  if (itemType !== undefined && !(itemType in ITEM_TYPE_PREMIUMS)) {
85	    throw new Error(`Item not in policy: ${itemType}`);
86	  }
87	};
88	
89	const processMultipleDamageEvents = (damageEvents: number[]): number => {
90	  let total = 0;
91	  let deductibleApplied = false;
92	  for (const event of damageEvents) {
93	    if (!deductibleApplied) {
94	      total += Math.max(0, event - CLAIM_DEDUCTIBLE);
95	      deductibleApplied = true;
96	    } else {
97	      total += event;
98	    }
99	  }
100	  return total;
101	};
102	
103	export function processClaim(damage: number, insuranceSum?: number, enchantmentLevel?: number, dragonMaterial?: boolean, itemType?: string, damageEvents?: number[], damagedQuantity?: number, insuredQuantity?: number): number {
104	  if (damage < 0) {
105	    throw new Error("Damage amount cannot be negative");
106	  }
107	  validateItemInPolicy(itemType);
108	  if (damagedQuantity !== undefined && insuredQuantity !== undefined && damagedQuantity > insuredQuantity) {
109	    throw new Error("Damaged quantity exceeds insured quantity");
110	  }
111	  if (damage === 0) {
112	    return 0;
113	  }
114	
115	  // Handle multiple damage events
116	  if (damageEvents !== undefined && damageEvents.length > 0) {
117	    return processMultipleDamageEvents(damageEvents);
118	  }
119	
120	  const afterDeductible = damage - CLAIM_DEDUCTIBLE;
121	  if (insuranceSum !== undefined) {
122	    const cappedAmount = applyInsuranceCap(afterDeductible, insuranceSum, dragonMaterial ?? false);
123	    return applyEnchantmentReduction(cappedAmount, enchantmentLevel);
124	  }
125	  return afterDeductible;
126	}
